/*! Local DayPilot Lite-compatible browser build (offline fallback) */
(function (global) {
  if (global.DayPilot && global.DayPilot.Scheduler && global.DayPilot.Date) {
    return;
  }

  function pad(v) {
    return String(v).padStart(2, "0");
  }

  function formatDate(value) {
    const date = value instanceof Date ? new Date(value.getFullYear(), value.getMonth(), value.getDate()) : new Date(value);
    if (Number.isNaN(date.getTime())) return "";
    return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
  }

  function parseDate(value) {
    if (value instanceof Date) return new Date(value.getFullYear(), value.getMonth(), value.getDate());
    if (typeof value === "string" && /^\d{4}-\d{2}-\d{2}$/.test(value)) {
      const [y, m, d] = value.split("-").map(Number);
      return new Date(y, m - 1, d);
    }
    return new Date(value);
  }

  class Scheduler {
    constructor(hostId, config) {
      this.hostId = hostId;
      Object.assign(this, config || {});
      this._initialized = false;
    }

    init() {
      this._initialized = true;
      this._render();
    }

    update() {
      this._render();
    }

    _render() {
      const host = document.getElementById(this.hostId);
      if (!host) return;

      const resources = Array.isArray(this.resources) ? this.resources : [];
      const events = Array.isArray(this.events) ? this.events : [];

      if (!resources.length) {
        host.innerHTML = '<div class="calendar-fallback-note">Нет данных для отображения планировщика.</div>';
        return;
      }

      const rows = resources
        .map((resource) => {
          const rowEvents = events.filter((event) => event.resource === resource.id);
          const items = rowEvents
            .map((event) => {
              const safeHtml = event.html || "";
              const start = formatDate(event.start);
              const end = formatDate(event.end);
              return `<button type="button" class="scheduler_default_event" data-event-id="${String(event.id || "")}" style="border-color:${event.borderColor || "#6366f1"};background:${event.backColor || "rgba(99,102,241,.2)"};color:${event.fontColor || "#f8fafc"}"><div class="scheduler_default_event_inner">${safeHtml}<div class="wrap-event-line" style="opacity:.7">${start}${end ? ` → ${end}` : ""}</div></div></button>`;
            })
            .join("");

          return `<div class="scheduler_default_rowheader"><div class="scheduler_default_rowheader_inner">${resource.name || "—"}</div></div><div class="scheduler_default_matrix">${items || '<div class="calendar-fallback-note">Событий нет.</div>'}</div>`;
        })
        .join("");

      host.innerHTML = `<div class="scheduler_default_main"><div class="scheduler_default_corner">Планировщик</div><div class="scheduler_default_colheader"><div class="scheduler_default_colheader_inner">${this.days || 0} дн.</div></div>${rows}</div>`;

      host.querySelectorAll("[data-event-id]").forEach((button) => {
        button.addEventListener("click", () => {
          const eventId = button.getAttribute("data-event-id");
          const eventData = events.find((event) => String(event.id) === String(eventId));
          if (typeof this.onEventClick === "function" && eventData) {
            this.onEventClick({ e: { data: eventData } });
          }
        });
      });
    }
  }

  global.DayPilot = {
    Date: {
      fromDatePart(value) {
        return formatDate(value);
      },
    },
    Scheduler,
  };
})(window);
